import sys, re
text = open(sys.argv[1]).read()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.S)
print(f"mermaid blocks: {len(blocks)}")
bad_in_label = []
for i, b in enumerate(blocks):
    for ln, line in enumerate(b.splitlines(), 1):
        s = line.strip()
        # check edge labels |"..."| and node labels [..]
        # find pipe-delimited edge labels
        for m in re.findall(r'\|"([^"]*)"\|', s):
            if re.search(r'[()\[\]:;/<>{}]', m):
                bad_in_label.append((i+1, ln, 'edge', m))
        # node labels: [Label], [[Label]], [(Label)]
        for m in re.findall(r'\[+\(?([^\[\]()]*?)\)?\]+', s):
            # skip classDef/class lines
            if s.startswith('class') or s.startswith('linkStyle'):
                continue
            if re.search(r'[:;/<>{}|]', m):
                bad_in_label.append((i+1, ln, 'node', m))
if bad_in_label:
    print("POTENTIAL BREAKING CHARS:")
    for x in bad_in_label:
        print("  ", x)
else:
    print("No breaking chars found inside node/edge labels.")
# Also flag any raw parentheses anywhere except classDef
print("\n--- lines with parens (excluding classDef/comments) ---")
for i,b in enumerate(blocks):
    for ln,line in enumerate(b.splitlines(),1):
        if '(' in line and 'fill' not in line and not line.strip().startswith('%%'):
            # cylinder [( )] is allowed syntax
            if not re.search(r'\[\([^)]*\)\]', line):
                print(f"  block{i+1} L{ln}: {line.strip()}")
